    with active_map as (
      select *
      from source_workflow_maps
      where document_id = ${docId}
        and status in ('validated','degraded')
        and superseded_by_map_id is null
      order by created_at desc
      limit 1
    ), map_elements as (
      select (active_map.id::text || ':node:' || (node.value->>'nodeId')) as ref, 'node' as kind
      from active_map, jsonb_array_elements(active_map.nodes_json) node(value)
      union all
      select (active_map.id::text || ':edge:' || (edge.value->>'edgeId')) as ref, 'edge' as kind
      from active_map, jsonb_array_elements(active_map.edges_json) edge(value)
    ), doc_claims as (
      select distinct c.id, c.status, c.map_element_ref, c.summary
      from claims c
      join claim_evidence ce on ce.claim_id = c.id
      join document_chunks dc on dc.id = ce.source_document_chunk_id
      where dc.document_id = ${docId}
    ), ref_counts as (
      select map_element_ref, count(*)::int as n
      from doc_claims
      where map_element_ref is not null
      group by map_element_ref
    ), coverage as (
      select
        count(*)::int as total_elements,
        count(rc.map_element_ref)::int as evidenced_elements,
        count(*) filter (where me.kind = 'node')::int as total_nodes,
        count(rc.map_element_ref) filter (where me.kind = 'node')::int as evidenced_nodes,
        count(*) filter (where me.kind = 'edge')::int as total_edges,
        count(rc.map_element_ref) filter (where me.kind = 'edge')::int as evidenced_edges
      from map_elements me
      left join ref_counts rc on rc.map_element_ref = me.ref
    ), orphan_refs as (
      select dc.map_element_ref, count(*)::int as n
      from doc_claims dc
      left join map_elements me on me.ref = dc.map_element_ref
      where dc.map_element_ref is not null and me.ref is null
      group by dc.map_element_ref
    ), duplicate_stats as (
      select coalesce(max(n), 0)::int as max_group, count(*) filter (where n >= 3)::int as elements_with_3_plus
      from ref_counts
    ), status_counts as (
      select status, count(*)::int as n from doc_claims group by status order by status
    )
    select
      (select id from active_map) as map_id,
      (select status from active_map) as map_status,
      (select created_at from active_map) as map_created_at,
      (select model_run_id from active_map) as map_model_run_id,
      (select jsonb_array_length(nodes_json) from active_map)::int as map_nodes,
      (select jsonb_array_length(edges_json) from active_map)::int as map_edges,
      (select count(*)::int from doc_claims) as promoted_claim_count,
      (select count(*)::int from doc_claims where map_element_ref is null) as null_refs,
      (select count(*)::int from orphan_refs) as orphan_ref_count,
      (select coalesce(jsonb_agg(jsonb_build_object('ref', map_element_ref, 'count', n) order by n desc), '[]'::jsonb) from orphan_refs) as orphan_refs,
      (select row_to_json(coverage) from coverage) as coverage,
      (select row_to_json(duplicate_stats) from duplicate_stats) as duplicate_stats,
      (select coalesce(jsonb_agg(status_counts), '[]'::jsonb) from status_counts) as claim_status_counts
